                                '<div class="preview-key"><strong>' + item.key + '</strong></div>' +
                                '<div class="preview-value">' + escapedValue + '</div>' +
                            '</div>' +
                            (item.description ? '<div class="text-gray font-size-12 margin-top-3">' + item.description + '</div>' : '') +
                        '</div>';
